import bz2, csv

types = {}
with bz2.open('sde/invTypes.csv.bz2', 'rt', encoding='utf-8') as f:
    for row in csv.DictReader(f):
        types[row['typeID']] = row

# Check what all hull sections produce via activity 8
relics = ['30752', '30753', '30754']  # Intact, Malfunctioning, Wrecked Hull Section
print('Products of Hull Sections (activity 8):')
with bz2.open('sde/industryActivityProducts.csv.bz2', 'rt', encoding='utf-8') as f:
    for row in csv.DictReader(f):
        if row['typeID'] in relics and row['activityID'] == '8':
            prod = types.get(row['productTypeID'], {})
            print(f\"  relic={row['typeID']}, product={prod.get('typeName','???')} ({row['productTypeID']}), qty={row['quantity']}\")

# Also check the skills for other hull sections
for relic_id in ['30753', '30754']:
    relic_name = types[relic_id]['typeName']
    print(f'\\nSkills for {relic_name} ({relic_id}), activity 8:')
    with bz2.open('sde/industryActivitySkills.csv.bz2', 'rt', encoding='utf-8') as f:
        for row in csv.DictReader(f):
            if row['typeID'] == relic_id and row['activityID'] == '8':
                skill = types.get(row['skillID'], {})
                print(f\"  skillID={row['skillID']}, name={skill.get('typeName','???')}\")

# Materials for all hull sections
for relic_id in ['30753', '30754']:
    relic_name = types[relic_id]['typeName']
    print(f'\\nMaterials for {relic_name} ({relic_id}), activity 8:')
    with bz2.open('sde/industryActivityMaterials.csv.bz2', 'rt', encoding='utf-8') as f:
        for row in csv.DictReader(f):
            if row['typeID'] == relic_id and row['activityID'] == '8':
                mat = types.get(row['materialTypeID'], {})
                print(f\"  name={mat.get('typeName','???')}, qty={row['quantity']}\")
"

